<script>
const userData = {
    name: '', identity: '', fears: [], scenario: '', scenarioType: '', scenarioDifficulty: '',
    isRandom: false, tarotCard: null, coinResult: null, dareTask: '', baseLuck: 50
};

const tarots = [
    { name: '愚者（正位）', luckModifier: 20, buff: '初始SAN-10，但拥有"初心庇护"（首次致命伤害可豁免）' },
    { name: '魔术师（逆位）', luckModifier: -15, buff: '获得神秘道具"欺诈之镜"（可复制一次NPC能力）' },
    { name: '倒吊人（正位）', luckModifier: 10, buff: '体力-20，但获得"逆境视角"（危机时可看见隐藏线索）' },
    { name: '死神（逆位）', luckModifier: -30, buff: '获得"重生契约"（死亡后可重置至最近存档点，仅限一次）' },
    { name: '恶魔（正位）', luckModifier: -20, buff: '获得"深渊低语"（可与非人存在短暂沟通）+恐惧免疫1次' },
    { name: '塔（正位）', luckModifier: -25, buff: '初始遭遇困难事件，但获得"废墟智慧"（破坏性行动成功率+30%）' },
    { name: '星星（正位）', luckModifier: 25, buff: '获得"希望之光"（可驱散一次黑暗/幻觉效果）' },
    { name: '月亮（逆位）', luckModifier: -10, buff: '获得"梦境直觉"（可提前感知即将发生的危险）' },
    { name: '太阳（正位）', luckModifier: 15, buff: '初始体力+20，获得"光明祝福"（队友信任度提升更快）' },
    { name: '审判（逆位）', luckModifier: -5, buff: '获得"罪孽感知"（可识别NPC的真实意图）' }
];

const coinOptions = [
    { result: '正面', luckModifier: 15, effect: '获得"幸运眷顾"（关键判定成功率+10%）' },
    { result: '反面', luckModifier: -15, effect: '触发"厄运纠缠"（首次遭遇强化）' }
];

const dares = [
    '【束缚】你必须在副本中说出一个真实的秘密（若违背，精神污染+20）',
    '【禁忌】你在副本中不能回头看（若违背，触发追击事件）',
    '【契约】你必须接受第一个NPC的邀请（无论其善恶）',
    '【服从】你不能拒绝任何直接请求（但可使用欺骗）',
    '【孤独】你必须独自行动（不可与其他玩家组队超过5分钟）',
    '【凝视】遇到镜子必须看三秒（可能触发"镜中人"事件）',
    '【沉默】在副本中不能主动发起对话（仅能回应他人）',
    '【真实】你不能说谎（包括善意的谎言）'
];

function clearAllSelections() {
    document.querySelectorAll('.scenario-item').forEach(i => i.classList.remove('selected'));
    document.getElementById('random-btn').classList.remove('selected');
}

document.querySelectorAll('.scenario-item').forEach(item => {
    item.addEventListener('click', function() {
        clearAllSelections();
        this.classList.add('selected');
        userData.scenario = this.dataset.scenario;
        userData.scenarioType = this.dataset.type;
        userData.scenarioDifficulty = this.dataset.difficulty;
        userData.isRandom = false;
        updateStatus();
    });
});

document.getElementById('random-btn').addEventListener('click', function() {
    clearAllSelections();
    this.classList.add('selected');
    userData.scenario = '随机生成';
    userData.scenarioType = '由深渊决定';
    userData.scenarioDifficulty = '未知';
    userData.isRandom = true;
    updateStatus();
});

document.getElementById('tarot-btn').addEventListener('click', function() {
    if (userData.tarotCard) { alert('⚠ 每人只能抽取一次塔罗牌'); return; }
    const card = tarots[Math.floor(Math.random() * tarots.length)];
    userData.tarotCard = card;
    document.getElementById('tarot-result').innerHTML = '🎴 <strong>' + card.name + '</strong><br>运气修正：' + (card.luckModifier > 0 ? '+' : '') + card.luckModifier + '%<br>特殊效果：' + card.buff;
    document.getElementById('tarot-result').classList.add('show');
    this.classList.add('played');
});

document.getElementById('coin-btn').addEventListener('click', function() {
    if (userData.coinResult) { alert('⚠ 命运之币只能抛掷一次'); return; }
    const coin = coinOptions[Math.floor(Math.random() * coinOptions.length)];
    userData.coinResult = coin;
    document.getElementById('coin-result').innerHTML = '🪙 <strong>' + coin.result + '</strong><br>运气修正：' + (coin.luckModifier > 0 ? '+' : '') + coin.luckModifier + '%<br>特殊效果：' + coin.effect;
    document.getElementById('coin-result').classList.add('show');
    this.classList.add('played');
});

document.getElementById('dare-btn').addEventListener('click', function() {
    if (userData.dareTask) { alert('⚠ 已接受冒险任务，无法更改'); return; }
    const dare = dares[Math.floor(Math.random() * dares.length)];
    userData.dareTask = dare;
    document.getElementById('dare-result').innerHTML = '💀 ' + dare;
    document.getElementById('dare-result').classList.add('show');
    this.classList.add('played');
});

function updateStatus() {
    const name = document.getElementById('user-name').value.trim();
    const hasScenario = userData.scenario !== '';
    let status = '💡 ';
    if (!name && !hasScenario) status += '请填写入馆登记并选择副本';
    else if (!name) status += '请填写你的称呼';
    else if (!hasScenario) status += '请选择一个副本';
    else status += userData.isRandom ? '✅ 准备就绪 — ' + name + ' · 🎲 让深渊决定' : '✅ 准备就绪 — ' + name + ' · ' + userData.scenario;
    document.getElementById('status-text').textContent = status;
}

document.getElementById('user-name').addEventListener('input', updateStatus);

function calculateFinalLuck() {
    let finalLuck = userData.baseLuck;
    if (userData.tarotCard) finalLuck += userData.tarotCard.luckModifier;
    if (userData.coinResult) finalLuck += userData.coinResult.luckModifier;
    return Math.max(0, Math.min(100, finalLuck));
}

function generateLuckBar(value) {
    const filled = Math.floor(value / 10);
    return '█'.repeat(filled) + '░'.repeat(10 - filled) + ' ' + value + '%';
}

document.getElementById('submit-btn').addEventListener('click', function() {
    userData.name = document.getElementById('user-name').value.trim();
    userData.identity = document.getElementById('user-identity').value.trim();
    userData.fears = Array.from(document.querySelectorAll('input[name="fear"]:checked')).map(function(cb) { return cb.value; });
    const customFear = document.getElementById('custom-fear').value.trim();
    if (customFear) userData.fears.push(customFear);

    if (!userData.name) { alert('❌ 请填写你的称呼'); return; }
    if (!userData.scenario) { alert('❌ 请选择一个副本'); return; }

    const finalLuck = calculateFinalLuck();
    const luckBar = generateLuckBar(finalLuck);

    let message = '【深渊酒馆·入馆数据】\n';
    message += '姓名=' + userData.name + '\n';
    message += '身份=' + (userData.identity || '未知旅人') + '\n';
    message += '恐惧=' + (userData.fears.join('、') || '无') + '\n';
    message += '副本=' + userData.scenario + '\n';
    message += '类型=' + userData.scenarioType + '\n';
    message += '难度=' + userData.scenarioDifficulty + '\n';
    message += '随机=' + userData.isRandom + '\n';
    message += '运气=' + finalLuck + '\n';
    message += '运气条=' + luckBar + '\n';
    message += '塔罗=' + (userData.tarotCard ? userData.tarotCard.name : '无') + '\n';
    message += '塔罗修正=' + (userData.tarotCard ? userData.tarotCard.luckModifier : 0) + '\n';
    message += '塔罗效果=' + (userData.tarotCard ? userData.tarotCard.buff : '无') + '\n';
    message += '硬币=' + (userData.coinResult ? userData.coinResult.result : '无') + '\n';
    message += '硬币修正=' + (userData.coinResult ? userData.coinResult.luckModifier : 0) + '\n';
    message += '硬币效果=' + (userData.coinResult ? userData.coinResult.effect : '无') + '\n';
    message += '冒险=' + (userData.dareTask || '无') + '\n';
    message += '【数据结束】\n\n';
    message += '我推开了深渊酒馆的门。';

    const debugBox = document.getElementById('debug-info');
    debugBox.style.display = 'block';
    debugBox.textContent = '===== 生成的消息 =====\n' + message;

    const btn = this;

    if (typeof triggerSlash === 'function') {
        btn.disabled = true;
        btn.textContent = '☾ 正在发送数据...';

        triggerSlash('/send ' + message);

        setTimeout(function() {
            btn.textContent = '☾ 等待AI回复...';
            triggerSlash('/trigger');
            debugBox.textContent += '\n\n✅ 已发送';
        }, 500);
    } else {
        debugBox.textContent += '\n\n⚠ 未检测到triggerSlash\n请手动复制消息';
        alert('【请手动复制消息】\n\n' + message);
    }
});
</script>

</body>
</html>
