<script>
(function() {
  function parseItems(id) {
    var raw = document.getElementById(id).textContent.trim();
    if (!raw || raw.includes('$')) return [];
    return raw.split('\n').map(function(line) {
      var parts = line.split('|');
      return parts.length >= 3 ? {
        name: parts[0].trim(),
        price: parseInt(parts[1]) || 0,
        desc: parts[2].trim(),
        stock: parts[3] ? parts[3].trim() : '可购买'
      } : null;
    }).filter(function(x) { return x; });
  }

  var pts = parseInt(document.getElementById('dataPoints').textContent.trim()) || 0;
  var db = {
    'consumables': parseItems('dataConsumables'),
    'skills': parseItems('dataSkillsShop'),
    'intel': parseItems('dataIntelShop'),
    'special': parseItems('dataSpecialShop'),
    'newArrivals': parseItems('dataNewArrivals')
  };

  document.getElementById('userPoints').textContent = pts;
  document.getElementById('inventoryDisplay').textContent = document.getElementById('dataInventory').textContent.replace(/\$/g,'') || '无';
  document.getElementById('skillsDisplay').textContent = document.getElementById('dataSkillsOwned').textContent.replace(/\$/g,'') || '无';

  var cart = {}, currentCategory = 'consumables', itemPage = 1, cartPage = 1;
  var shopPerPage = 5, cartPerPage = 3;

  function renderNewArrivals() {
    var container = document.getElementById('newArrivalsList'), section = document.getElementById('newArrivalsSection');
    if (db.newArrivals.length === 0) { section.style.display = 'none'; return; }
    section.style.display = 'block';
    container.innerHTML = db.newArrivals.map(function(item) {
      return `<div style="flex: 1; min-width: 200px; background: rgba(0,0,0,0.4); border: 1px solid rgba(180,130,200,0.3); border-radius: 6px; padding: 12px;">
        <div style="display: flex; justify-content: space-between; align-items: start; margin-bottom: 8px;">
          <div><div style="color: #d4a8e8; font-size: 13px; margin-bottom: 4px;">${item.name}</div><div style="font-size: 10px; color: #7a6a6a;">${item.desc}</div></div>
          <div style="font-size: 15px; color: #d4a8e8;">${item.price}</div>
        </div>
        <button onclick="window.shopAddToCart('${item.name.replace(/'/g, "\\'")}', ${item.price})" style="width: 100%; padding: 6px; background: rgba(180,130,200,0.25); border: 1px solid rgba(180,130,200,0.3); border-radius: 3px; color: white; cursor: pointer; font-size: 10px;">➕ 加入购物车</button>
      </div>`;
    }).join('');
  }

  window.renderItems = function() {
    var list = db[currentCategory], container = document.getElementById('itemList');
    var total = Math.ceil(list.length / shopPerPage) || 1;
    var items = list.slice((itemPage-1)*shopPerPage, itemPage*shopPerPage);
    document.getElementById('pageIndicator').textContent = '共 ' + list.length + ' 件';
    if (!items.length) { container.innerHTML = '<div style="text-align: center; color: #7a6a6a; padding: 20px;">暂无商品</div>'; document.getElementById('itemPagination').style.display = 'none'; return; }
    container.innerHTML = items.map(function(item) {
      var lock = item.stock.indexOf('解锁') !== -1 || item.stock === '售罄';
      return `<div style="background: rgba(0,0,0,0.3); border: 1px solid rgba(139,107,97,0.2); border-radius: 4px; padding: 14px; margin-bottom: 10px; ${lock?'opacity:0.5':''}">
        <div style="display: flex; justify-content: space-between; margin-bottom: 8px;">
          <div style="flex: 1;"><div style="font-size: 14px; color: #c9a87c; margin-bottom: 4px;">${item.name}</div><div style="font-size: 11px; color: #7a6a6a;">${item.desc}</div></div>
          <div style="text-align: right;"><div style="font-size: 16px; color: #c9a87c;">${item.price}</div><div style="font-size: 9px; color: #6b5555;">${item.stock}</div></div>
        </div>
        <button onclick="window.shopAddToCart('${item.name.replace(/'/g, "\\'")}', ${item.price})" ${lock?'disabled':''} style="width: 100%; padding: 8px; background: ${lock?'rgba(0,0,0,0.2)':'rgba(139,107,97,0.3)'}; border: 1px solid rgba(139,107,97,0.3); border-radius: 3px; color: white; cursor: pointer; font-size: 11px;">${lock?item.stock:'➕ 加入购物车'}</button>
      </div>`;
    }).join('');
    document.getElementById('itemPagination').style.display = total > 1 ? 'flex' : 'none';
    document.getElementById('itemPageInfo').textContent = itemPage + ' / ' + total;
  };

  window.itemPrevPage = function() { if (itemPage > 1) { itemPage--; renderItems(); } };
  window.itemNextPage = function() { if (itemPage < Math.ceil(db[currentCategory].length/shopPerPage)) { itemPage++; renderItems(); } };

  window.switchCategory = function(cat) {
    currentCategory = cat; itemPage = 1;
    document.getElementById('currentCategory').textContent = {consumables:'消耗品', skills:'永久技能', intel:'情报', special:'特殊'}[cat];
    ['consumables', 'skills', 'intel', 'special'].forEach(function(c) {
      var t = document.getElementById('tab-' + c);
      if (t) { t.style.background = (c === cat) ? 'rgba(201,168,124,0.2)' : 'rgba(0,0,0,0.2)'; t.style.color = (c === cat) ? '#c9a87c' : '#7a6a6a'; }
    });
    renderItems();
  };

  window.shopAddToCart = function(n, p) { if (cart[n]) cart[n].quantity++; else cart[n] = { price: p, quantity: 1 }; updateCart(); showMessage('已添加【' + n + '】'); };

  function updateCart() {
    var c = document.getElementById('cartContent'), t = document.getElementById('cartTotal'), ks = Object.keys(cart);
    if (!ks.length) { c.innerHTML = '<div style="padding: 20px 0;">购物车为空</div>'; t.textContent = '0'; document.getElementById('cartPagination').style.display = 'none'; return; }
    var total = 0; ks.forEach(function(k) { total += cart[k].price * cart[k].quantity; }); t.textContent = total;
    var tp = Math.ceil(ks.length / cartPerPage); if (cartPage > tp) cartPage = tp;
    c.innerHTML = ks.slice((cartPage-1)*cartPerPage, cartPage*cartPerPage).map(function(n) {
      return `<div style="display: flex; justify-content: space-between; padding: 8px 14px; border-bottom: 1px dashed rgba(139,107,97,0.15);">
        <div><div style="font-size: 12px; color: #e8e0d5;">${n}</div><div style="font-size: 10px; color: #6b5555;">${cart[n].price} × ${cart[n].quantity}</div></div>
        <div style="display: flex; align-items: center; gap: 8px;"><div style="font-size: 13px; color: #c9a87c;">${cart[n].price * cart[n].quantity}</div><button onclick="window.shopRemove('${n.replace(/'/g, "\\'")}')" style="background:none; border:none; color:#c98a8a; cursor:pointer;">✕</button></div>
      </div>`;
    }).join('');
    document.getElementById('cartPagination').style.display = tp > 1 ? 'flex' : 'none';
    document.getElementById('cartPageInfo').textContent = cartPage + ' / ' + tp;
  }

  window.shopRemove = function(n) { delete cart[n]; updateCart(); };
  window.clearCart = function() { cart = {}; cartPage = 1; updateCart(); };
  window.cartPrevPage = function() { if (cartPage > 1) { cartPage--; updateCart(); } };
  window.cartNextPage = function() { if (cartPage < Math.ceil(Object.keys(cart).length/cartPerPage)) { cartPage++; updateCart(); } };

  // --- 核心注入：回归 /send (User) ---
  window.checkout = function() {
    var ks = Object.keys(cart); if (!ks.length) return;
    var total = parseInt(document.getElementById('cartTotal').textContent);
    if (pts < total) { showMessage('❌ 积分不足', 'error'); return; }
    var req = '【购买请求】购买：' + ks.map(function(k) { return k + '×' + cart[k].quantity; }).join('、') + '，总计' + total + '积分。请帮我结算。';

    if (typeof triggerSlash === 'function') {
      try {
        // 使用 /send 将消息作为用户发送
        triggerSlash('/send ' + req);
        // 使用 /trigger 或 /gen 触发 AI 回复
        setTimeout(function() { triggerSlash('/trigger'); }, 100);
        window.clearCart(); showMessage('✅ 购买请求已发出', 'success'); return;
      } catch (e) { console.error(e); }
    }
  };

  function showMessage(t, type) {
    var el = document.getElementById('shopMessage'); el.textContent = t; el.style.display = 'block';
    el.style.color = (type === 'error') ? '#c98a8a' : '#c9a87c';
    setTimeout(function() { el.style.display = 'none'; }, 2000);
  }

  renderNewArrivals(); renderItems();
})();
</script>
</html>
