}

// 渲染技能列表
function renderSkills() {
  const container = document.getElementById('skills');
  const filtered = skillsData.filter(s => s.category === currentTree.replace('系', ''));

  container.innerHTML = filtered.map(skill => {
    const isMaxLevel = skill.currentLevel >= skill.maxLevel;
    const isLocked = skill.status.includes('解锁');
    const canUpgrade = !isMaxLevel && !isLocked && skill.status !== '已解锁' || skill.currentLevel > 0;
    const nextLevelCost = calculateUpgradeCost(skill);

    return `
      <div style="background: rgba(0,0,0,0.3); border: 1px solid ${getSkillBorderColor(skill)}; border-radius: 6px; padding: 16px; margin-bottom: 12px; position: relative; ${isLocked ? 'opacity: 0.6;' : ''}">

        <!-- 技能状态徽章 -->
        <div style="position: absolute; top: 12px; right: 12px; padding: 4px 12px; background: ${getStatusBg(skill.status)}; border: 1px solid ${getStatusBorder(skill.status)}; border-radius: 3px; font-size: 9px; color: ${getStatusColor(skill.status)}; letter-spacing: 1px;">
          ${getStatusText(skill)}
        </div>

        <!-- 技能名称与等级 -->
        <div style="margin-bottom: 12px; padding-right: 80px;">
          <div style="font-size: 16px; color: #c9a87c; margin-bottom: 6px; letter-spacing: 1px; font-weight: 500;">${skill.name}</div>
          <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 8px;">
            <div style="flex: 1; height: 6px; background: rgba(0,0,0,0.4); border-radius: 3px; overflow: hidden;">
              <div style="height: 100%; background: linear-gradient(90deg, #8b6b61, #c9a87c); width: ${(skill.currentLevel / skill.maxLevel) * 100}%; transition: width 0.3s ease;"></div>
            </div>
            <span style="font-size: 11px; color: #c9a87c; font-weight: 500; min-width: 50px; text-align: right;">Lv ${skill.currentLevel}/${skill.maxLevel}</span>
          </div>
          <div style="font-size: 11px; color: #7a6a6a; line-height: 1.6;">${skill.desc}</div>
        </div>

        <!-- 升级按钮 -->
        <div style="display: flex; gap: 10px; align-items: center;">
          ${canUpgrade && !isLocked ? `
            <button onclick="addToUpgradeQueue('${skill.name}')" ${isMaxLevel ? 'disabled' : ''} style="flex: 1; padding: 10px 16px; background: ${isMaxLevel ? 'rgba(0,0,0,0.2)' : 'rgba(139,107,97,0.3)'}; border: 1px solid rgba(139,107,97,0.3); border-radius: 4px; color: ${isMaxLevel ? '#5a4a4a' : '#c9a87c'}; font-size: 12px; cursor: ${isMaxLevel ? 'not-allowed' : 'pointer'}; letter-spacing: 1px; transition: all 0.2s;">
              ${isMaxLevel ? '✓ 已满级' : `⬆ 升级 (${nextLevelCost} 积分)`}
            </button>
          ` : ''}
          ${skill.status === '可购买' ? `
            <button onclick="purchaseSkill('${skill.name}')" style="flex: 1; padding: 10px 16px; background: linear-gradient(135deg, #8b6b61, #c9a87c); border: none; border-radius: 4px; color: #1a1215; font-size: 12px; font-weight: 500; cursor: pointer; letter-spacing: 1px;">
              💰 购买 (${skill.basePrice} 积分)
            </button>
          ` : ''}
          ${isLocked ? `
            <div style="flex: 1; padding: 10px 16px; background: rgba(139,0,0,0.2); border: 1px solid rgba(139,0,0,0.3); border-radius: 4px; color: #c98a8a; font-size: 11px; text-align: center; letter-spacing: 1px;">
              🔒 ${skill.status}
            </div>
          ` : ''}
        </div>
      </div>
    `;
  }).join('');
}

// 计算升级费用
function calculateUpgradeCost(skill) {
  // 升级费用递增：基础价 * (1 + 当前等级 * 0.5)
  return Math.floor(skill.basePrice * (1 + skill.currentLevel * 0.5));
}

// 获取技能边框颜色
function getSkillBorderColor(skill) {
  if (skill.currentLevel >= skill.maxLevel) return 'rgba(107,139,107,0.4)';
  if (skill.status.includes('解锁')) return  'rgba(139,0,0,0.3)';
  return 'rgba(139,107,97,0.2)';
}

// 获取状态背景色
function getStatusBg(status) {
  if (status === '已解锁') return 'rgba(107,139,107,0.2)';
  if (status === '可购买') return 'rgba(201,168,124,0.2)';
  return 'rgba(139,0,0,0.15)';
}

// 获取状态边框色
function getStatusBorder(status) {
  if (status === '已解锁') return 'rgba(107,139,107,0.3)';
  if (status === '可购买') return 'rgba(201,168,124,0.3)';
  return 'rgba(139,0,0,0.3)';
}

// 获取状态文字色
function getStatusColor(status) {
  if (status === '已解锁') return '#8bab8b';
  if (status === '可购买') return '#c9a87c';
  return '#c98a8a';
}

// 获取状态文本
function getStatusText(skill) {
  if (skill.currentLevel >= skill.maxLevel) return '✓ 满级';
  return skill.status;
}

// 添加到升级队列
function addToUpgradeQueue(skillName) {
  const skill = skillsData.find(s => s.name === skillName);
  if (!skill) return;

  const cost = calculateUpgradeCost(skill);

  if (userPoints < cost) {
    showMessage(`积分不足！需要 ${cost} 积分`, 'error');
    return;
  }

  if (upgradeQueue.find(s => s.name === skillName)) {
    showMessage('该技能已在升级队列中', 'error');
    return;
  }

  upgradeQueue.push({
    name: skillName,
    cost: cost,
    fromLevel: skill.currentLevel,
    toLevel: skill.currentLevel + 1
  });

  updateQueueDisplay();
  showMessage(`已将 ${skillName} 加入升级队列`, 'info');
}

// 更新队列显示
function updateQueueDisplay() {
  const queueDiv = document.getElementById('upgradeQueue');
  const contentDiv = document.getElementById('queueContent');

  if (upgradeQueue.length === 0) {
    queueDiv.style.display = 'none';
    return;
  }

  queueDiv.style.display = 'block';

  const totalCost = upgradeQueue.reduce((sum, s) => sum + s.cost, 0);

  contentDiv.innerHTML = `
    ${upgradeQueue.map((item, index) => `
      <div style="display: flex; justify-content: space-between; align-items: center; padding: 8px 0; border-bottom: 1px dashed rgba(139,107,97,0.15);">
        <div>
          <div style="font-size: 12px; color: #e8e0d5;">${item.name}</div>
          <div style="font-size: 10px; color: #6b5555; margin-top: 2px;">Lv ${item.fromLevel} → Lv ${item.toLevel}</div>
        </div>
        <div style="display: flex; align-items: center; gap: 10px;">
          <div style="font-size: 13px; color: #c9a87c; font-weight: 500;">${item.cost}</div>
          <button onclick="removeFromQueue(${index})" style="padding: 4px 8px; background: rgba(139,0,0,0.3); border: 1px solid rgba(139,0,0,0.4); border-radius: 3px; color: #c98a8a; font-size: 10px; cursor: pointer;">✕</button>
        </div>
      </div>
    `).join('')}
    <div style="display: flex; justify-content: space-between; align-items: center; padding-top: 12px; margin-top: 8px; border-top: 1px solid rgba(139,107,97,0.25);">
      <span style="font-size: 12px; color: #8b6b61; letter-spacing: 1px;">合计</span>
      <span style="font-size: 16px; color: #c9a87c; font-weight: 500;">${totalCost} 积分</span>
    </div>
  `;
}

// 从队列移除
function removeFromQueue(index) {
  upgradeQueue.splice(index, 1);
  updateQueueDisplay();
  showMessage('已从队列中移除', 'info');
}

// 清空队列
function clearQueue() {
  if (upgradeQueue.length === 0) return;
  upgradeQueue = [];
  updateQueueDisplay();
  showMessage('升级队列已清空', 'info');
}

// 确认升级
function confirmUpgrade() {
  if (upgradeQueue.length === 0) {
    showMessage('升级队列为空', 'error');
    return;
  }

  const totalCost = upgradeQueue.reduce((sum, s) => sum + s.cost, 0);

  if (userPoints < totalCost) {
    showMessage(`积分不足！需要 ${totalCost} 积分`, 'error');
    return;
  }

  // 生成确认消息
  const upgradeList = upgradeQueue.map(s => `${s.name} Lv${s.fromLevel}→Lv${s.toLevel}`).join('、');
  sendUpgradeMessage(`确认升级：${upgradeList}`);
}

// 购买技能
function purchaseSkill(skillName) {
  const skill = skillsData.find(s => s.name === skillName);
  if (!skill) return;

  if (userPoints < skill.basePrice) {
    showMessage(`积分不足！需要 ${skill.basePrice} 积分`, 'error');
    return;
  }

  sendUpgradeMessage(`购买技能：${skillName}`);
}

// 切换技能树
function switchTree(treeName) {
  if (treeName === currentTree) return;
  sendUpgradeMessage(`切换到${treeName}`);
}

// 发送升级消息
function sendUpgradeMessage(msg) {
  showMessage(`请在输入框确认："${msg}"`);
}

// 显示消息
function showMessage(text, type = 'info') {
  const msgEl = document.getElementById('skillMessage');
  msgEl.textContent = text;
  msgEl.style.display = 'block';

  if (type === 'error') {
    msgEl.style.background = 'rgba(139,0,0,0.2)';
    msgEl.style.borderColor = 'rgba(139,0,0,0.3)';
    msgEl.style.color = '#c98a8a';
  } else if (type === 'success') {
    msgEl.style.background = 'rgba(107,139,107,0.2)';
    msgEl.style.borderColor = 'rgba(107,139,107,0.3)';
    msgEl.style.color = '#8bab8b';
  } else {
    msgEl.style.background = 'rgba(201,168,124,0.1)';
    msgEl.style.borderColor = 'rgba(201,168,124,0.2)';
    msgEl.style.color = '#c9a87c';
  }

  setTimeout(() => {
    msgEl.style.display = 'none';
  }, 3000);
}

// 初始化
parseSkills();
</script>
</html>
